import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';

// 保持原有的 lessonData 数据不变...

export default function VideoPage() {
  const { id } = useParams();
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, [id]);
  
  const navigate = useNavigate();
  const currentId = parseInt(id || "1");
  const maxLessonId = Object.keys(lessonData).length;
  const nextId = currentId + 1 > maxLessonId ? 1 : currentId + 1;

  const { videoUrl, quiz } = lessonData[currentId] || lessonData[1];

  const [answers, setAnswers] = useState(Array(quiz.length).fill(null));
  const [submitted, setSubmitted] = useState(false);
  const [aiHelpIndex, setAiHelpIndex] = useState(null);

  const handleOptionChange = (index, option) => {
    const newAnswers = [...answers];
    newAnswers[index] = option;
    setAnswers(newAnswers);
  };

  const handleSubmit = () => {
    setSubmitted(true);
    setAiHelpIndex(null);
  };

  const score = answers.reduce((acc, cur, idx) => {
    return cur === quiz[idx].answer ? acc + 2 : acc;
  }, 0);

  // 动态样式函数
  const getSubmitButtonStyle = (disabled) => ({
    width: '100%',
    padding: '0.8em',
    backgroundColor: disabled ? '#bdbdbd' : '#4fb3bf',
    color: 'white',
    border: 'none',
    borderRadius: '8px',
    fontSize: '1em',
    cursor: disabled ? 'not-allowed' : 'pointer',
    transition: 'all 0.2s',
    marginTop: '1em'
  });

  const getNavButtonStyle = (hover = false) => ({
    padding: '0.6em 1.2em',
    backgroundColor: hover ? '#00838f' : '#4fb3bf',
    color: 'white',
    border: 'none',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '1em',
    transition: 'all 0.2s'
  });

  const getHelpButtonStyle = (hover = false) => ({
    marginTop: '0.8em',
    padding: '0.4em 1em',
    backgroundColor: hover ? '#bbdefb' : '#e3f2fd',
    color: '#1565c0',
    border: 'none',
    borderRadius: '20px',
    cursor: 'pointer',
    fontSize: '0.9em',
    transition: 'all 0.2s'
  });

  // 静态样式
  const containerStyle = {
    padding: '1.5em',
    fontFamily: 'Arial, sans-serif',
    maxWidth: '800px',
    margin: '0 auto',
  };

  const titleStyle = {
    textAlign: 'center',
    marginBottom: '1em',
    color: '#00796b',
    fontSize: '1.5em'
  };

  const videoWrapperStyle = {
    marginBottom: '2em',
    borderRadius: '12px',
    overflow: 'hidden',
    boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
    backgroundColor: '#000'
  };

  const quizSectionStyle = {
    marginBottom: '1.5em'
  };

  const questionBlockStyle = {
    marginBottom: '1.5em',
    backgroundColor: '#fff',
    padding: '1.2em',
    borderRadius: '10px',
    boxShadow: '0 2px 8px rgba(0,0,0,0.05)'
  };

  const questionTextStyle = {
    fontSize: '1.1em',
    marginBottom: '0.8em',
    color: '#333'
  };

  const optionsContainerStyle = {
    marginLeft: '0.5em'
  };

  const optionStyle = {
    display: 'flex',
    alignItems: 'center',
    margin: '0.5em 0',
    cursor: 'pointer'
  };

  const radioInputStyle = {
    marginRight: '0.8em',
    cursor: 'pointer'
  };

  const optionTextStyle = {
    fontSize: '1em'
  };

  const wrongAnswerStyle = {
    color: '#d32f2f',
    backgroundColor: '#ffebee',
    padding: '0.8em',
    borderRadius: '6px',
    marginTop: '0.8em'
  };

  const aiResponseStyle = {
    marginTop: '0.8em',
    backgroundColor: '#e8f5e9',
    padding: '0.8em',
    borderRadius: '6px',
    borderLeft: '4px solid #4caf50'
  };

  const aiTextStyle = {
    margin: 0,
    color: '#2e7d32'
  };

  const actionBarStyle = {
    marginTop: '1.5em'
  };

  const resultContainerStyle = {
    textAlign: 'center'
  };

  const scoreStyle = {
    fontSize: '1.2em',
    marginBottom: '1em',
    color: '#00796b'
  };

  const navigationStyle = {
    display: 'flex',
    justifyContent: 'center',
    gap: '1em'
  };

  return (
    <div className="content-card">
      <div style={containerStyle}>
        <h2 style={titleStyle}>📹 Lesson {currentId} - Watch & Quiz</h2>

        {/* 视频区域 */}
        <div style={videoWrapperStyle}>
          <iframe
            width="100%"
            height="400"
            src={videoUrl}
            title={`Lesson ${currentId}`}
            frameBorder="0"
            allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
            allowFullScreen
          ></iframe>
        </div>

        {/* 问题区 */}
        <div style={quizSectionStyle}>
          {quiz.map((q, index) => (
            <div key={index} style={questionBlockStyle}>
              <p style={questionTextStyle}><strong>{q.question}</strong></p>
              <div style={optionsContainerStyle}>
                {q.options.map((opt, optIdx) => (
                  <label key={optIdx} style={optionStyle}>
                    <input
                      type="radio"
                      name={`question-${index}`}
                      value={optIdx}
                      disabled={submitted}
                      checked={answers[index] === optIdx}
                      onChange={() => handleOptionChange(index, optIdx)}
                      style={radioInputStyle}
                    />
                    <span style={optionTextStyle}>{opt}</span>
                  </label>
                ))}
              </div>
              
              {submitted && answers[index] !== q.answer && (
                <p style={wrongAnswerStyle}>❌ {q.help}</p>
              )}
              
              {!submitted && (
                <button
                  style={getHelpButtonStyle()}
                  onMouseEnter={(e) => e.target.style.backgroundColor = '#bbdefb'}
                  onMouseLeave={(e) => e.target.style.backgroundColor = '#e3f2fd'}
                  onClick={() => setAiHelpIndex(aiHelpIndex === index ? null : index)}
                >
                  {aiHelpIndex === index ? '🤖 Hide Hint' : '🤖 Get Hint'}
                </button>
              )}
              
              {aiHelpIndex === index && (
                <div style={aiResponseStyle}>
                  <p style={aiTextStyle}>{q.help}</p>
                </div>
              )}
            </div>
          ))}
        </div>

        {/* 提交与导航 */}
        <div style={actionBarStyle}>
          {!submitted ? (
            <button 
              style={getSubmitButtonStyle(answers.some(a => a === null))}
              onClick={handleSubmit}
              disabled={answers.some(a => a === null)}
            >
              Submit Answers
            </button>
          ) : (
            <div style={resultContainerStyle}>
              <p style={scoreStyle}>Your score: <strong>{score}/{quiz.length * 2}</strong></p>
              <div style={navigationStyle}>
                <button
                  style={getNavButtonStyle()}
                  onMouseEnter={(e) => e.target.style.backgroundColor = '#00838f'}
                  onMouseLeave={(e) => e.target.style.backgroundColor = '#4fb3bf'}
                  onClick={() => navigate(`/video/${currentId > 1 ? currentId - 1 : maxLessonId}`)}
                >
                  ◀️ Previous
                </button>
                <button
                  style={getNavButtonStyle()}
                  onMouseEnter={(e) => e.target.style.backgroundColor = '#00838f'}
                  onMouseLeave={(e) => e.target.style.backgroundColor = '#4fb3bf'}
                  onClick={() => navigate(`/video/${nextId}`)}
                >
                  Next ▶️
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
